questions.questionText:
What is the output?

const nums = [1, 2, 3];
const [a, b] = nums;
console.log(a, b);

What is the output?

const { a, b = 10 } = { a: 5 };
console.log(a, b);

What is the output?

const [x = 1, y = 2, z = 3] = [10, undefined];
console.log(x, y, z);

What is the output?

const obj = { a: 1, b: 2 };
const { a, ...rest } = obj;
console.log(a, rest);

What is the output?

const map = new Map([['a', 1], ['b', 2]]);
map.set('c', 3);
map.delete('a');
console.log([...map.keys()], [...map.values()]);

What does the following generator produce?

function* fibonacci() {
  let [a, b] = [0, 1];
  while (true) {
    yield a;
    [a, b] = [b, a + b];
  }
}
const gen = fibonacci();
console.log([...Array(5)].map(() => gen.next().value));

What is the output?

const s = new Set([1, 2, 2, 3, 3, 3]);
const arr = [...s].map(x => x * 2);
console.log(arr);

What is the output?

const obj = { a: 1, b: 2 };
console.log(Object.keys(obj).length + Object.values(obj).reduce((a, b) => a + b, 0));

What is the output?

const map = new Map();
map.set('a', 1);
map.set('b', 2);
map.set('a', 3);  // duplicate key
console.log(map.size);

What is the output?

function* numbers() {
  yield 1;
  yield 2;
  return 3;
}
const gen = numbers();
const [a, b] = gen;
console.log(a, b);

What is the output?

const arr = [1, 2, 3];
const [head, ...rest] = arr;
const [first, ...second] = rest;
console.log(head, first, second);

What is the output?

class A {
  constructor() { this.x = 1; }
  method() { return this.x; }
}
class B extends A {
  constructor() { super(); this.x = 2; }
  method() { return super.method() + this.x; }
}
console.log(new B().method());
